import { Request, Response } from 'express';
import { UserService } from '../services/UserService';
import { UserRepository } from '../repositories/UserRepository';
import { UserValidator } from '../validators/UserValidator';
import { Logger } from '../utils/Logger';

export class UserController {
  private userService: UserService;
  private validator: UserValidator;
  private logger: Logger;

  constructor() {
    const db = new UserRepository();
    this.userService = new UserService(db);
    this.validator = new UserValidator();
    this.logger = new Logger('UserController');
  }

  async createUser(req: Request, res: Response): Promise<void> {
    try {
      const userData = req.body;

      if (!this.validator.validate(userData)) {
        res.status(400).json({ error: 'Invalid user data' });
        return;
      }

      const user = await this.userService.createUser(userData);
      this.logger.info('User created', { userId: user.id });

      res.status(201).json({
        id: user.id,
        email: user.email,
        createdAt: user.createdAt
      });
    } catch (error) {
      this.logger.error('Failed to create user', error);
      res.status(500).json({ error: 'Internal server error' });
    }
  }

  async getUser(req: Request, res: Response): Promise<void> {
    const user = await this.userService.findById(req.params.id);
    if (!user) {
      res.status(404).json({ error: 'User not found' });
      return;
    }
    res.json(user);
  }
}

// Port interface - domain logic depends on this
class UserDomainService {
  private userPort: UserPort;
  private notificationPort: NotificationPort;

  constructor(userPort: UserPort, notificationPort: NotificationPort) {
    this.userPort = userPort;
    this.notificationPort = notificationPort;
  }

  async registerUser(email: string, password: string): Promise<User> {
    // Domain logic
    const existingUser = await this.userPort.findByEmail(email);
    if (existingUser) {
      throw new ConflictError('Email already exists');
    }

    const hashedPassword = await this.hashPassword(password);
    const user = User.create({
      email,
      passwordHash: hashedPassword,
      createdAt: new Date()
    });

    const savedUser = await this.userPort.save(user);

    // Notify other systems
    await this.notificationPort.sendWelcomeEmail(email);

    return savedUser;
  }
}

