interface DomainEvent {
  eventType: string;
  aggregateId: string;
  timestamp: Date;
  payload: any;
  version: number;
}

class EventStore {
  private events: Map<string, DomainEvent[]> = new Map();
  private subscribers: Map<string, Set<(event: DomainEvent) => void>> = new Map();

  appendEvent(aggregateId: string, event: DomainEvent): void {
    if (!this.events.has(aggregateId)) {
      this.events.set(aggregateId, []);
    }

    const eventHistory = this.events.get(aggregateId)!;
    event.version = eventHistory.length + 1;
    eventHistory.push(event);

    // Notify subscribers
    const eventSubscribers = this.subscribers.get(event.eventType);
    if (eventSubscribers) {
      eventSubscribers.forEach(subscriber => subscriber(event));
    }
  }

  getEvents(aggregateId: string, fromVersion?: number): DomainEvent[] {
    const events = this.events.get(aggregateId) || [];
    if (fromVersion !== undefined) {
      return events.filter(e => e.version > fromVersion);
    }
    return [...events];
  }

  subscribeToEvent(eventType: string, handler: (event: DomainEvent) => void): void {
    if (!this.subscribers.has(eventType)) {
      this.subscribers.set(eventType, new Set());
    }
    this.subscribers.get(eventType)!.add(handler);
  }

  rebuildState(aggregateId: string): any {
    const events = this.getEvents(aggregateId);
    let state = {};

    for (const event of events) {
      state = this.applyEvent(state, event);
    }

    return state;
  }

  private applyEvent(currentState: any, event: DomainEvent): any {
    switch (event.eventType) {
      case 'UserCreated':
        return { ...currentState, ...event.payload };
      case 'UserUpdated':
        return { ...currentState, ...event.payload };
      case 'UserDeleted':
        return { ...currentState, deleted: true };
      default:
        return currentState;
    }
  }
}

class RouteConfig {
  path: string;
  methods: string[];
  service: string;
  authRequired: boolean;
  rateLimit?: number;
  timeout?: number;
}

class GatewayServer {
  private routes: Map<string, RouteConfig> = new Map();
  private services: Map<string, ServiceClient> = new Map();
  private middlewares: Middleware[] = [];

  registerRoute(config: RouteConfig): void {
    this.routes.set(`${config.methods.join(',').toUpperCase()}:${config.path}`, config);
  }

  registerService(name: string, client: ServiceClient): void {
    this.services.set(name, client);
  }

  addMiddleware(middleware: Middleware): void {
    this.middlewares.push(middleware);
  }

  async handleRequest(request: GatewayRequest): Promise<GatewayResponse> {
    const routeKey = `${request.method}:${request.path}`;
    const route = this.routes.get(routeKey);

    if (!route) {
      return { status: 404, body: { error: 'Route not found' } };
    }

    // Execute middleware chain
    for (const middleware of this.middlewares) {
      const result = await middleware.handle(request, route);
      if (result instanceof GatewayResponse) {
        return result;
      }
    }

    // Forward to service
    const service = this.services.get(route.service);
    if (!service) {
      return { status: 500, body: { error: 'Service not available' } };
    }

    return service.forward(request);
  }
}

