interface MicroFrontendModule {
  name: string;
  version: string;
  mount(container: HTMLElement): void;
  unmount(container: HTMLElement): void;
}

class ModuleRegistry {
  private modules: Map<string, MicroFrontendModule> = new Map();

  register(module: MicroFrontendModule): void {
    this.modules.set(module.name, module);
  }

  get(name: string): MicroFrontendModule | undefined {
    return this.modules.get(name);
  }
}

class AppHost {
  private registry: ModuleRegistry;
  private activeModules: Map<string, HTMLElement> = new Map();

  constructor() {
    this.registry = new ModuleRegistry();
  }

  async loadModule(moduleName: string, remoteUrl: string): Promise<void> {
    const module = await import(/* webpackChunkName: "[request]" */ remoteUrl);
    this.registry.register(module.default);
  }

  mountModule(moduleName: string, containerId: string): void {
    const module = this.registry.get(moduleName);
    if (!module) {
      throw new Error(`Module ${moduleName} not found`);
    }

    const container = document.getElementById(containerId);
    if (!container) {
      throw new Error(`Container ${containerId} not found`);
    }

    module.mount(container);
    this.activeModules.set(moduleName, container);
  }

  unmountAll(): void {
    this.activeModules.forEach((container, moduleName) => {
      const module = this.registry.get(moduleName);
      if (module) {
        module.unmount(container);
      }
    });
    this.activeModules.clear();
  }
}

export { AppHost, ModuleRegistry };

interface LambdaContext {
  functionName: string;
  memoryLimitInMB: number;
  awsRequestId: string;
  log: (message: string) => void;
}

class ServerlessHandler {
  private handlers: Map<string, HandlerFunction> = new Map();

  register(eventType: string, handler: HandlerFunction): void {
    this.handlers.set(eventType, handler);
  }

  async invoke(event: any, context: LambdaContext): Promise<any> {
    const handler = this.handlers.get(event.eventType);
    if (!handler) {
      throw new Error(`No handler registered for event type: ${event.eventType}`);
    }

    context.log(`Invoking handler for ${event.eventType}`);
    const startTime = Date.now();

    try {
      const result = await handler(event, context);
      const duration = Date.now() - startTime;
      context.log(`Handler completed in ${duration}ms`);
      return result;
    } catch (error) {
      context.log(`Handler failed: ${error.message}`);
      throw error;
    }
  }
}

type HandlerFunction = (event: any, context: LambdaContext) => Promise<any>;

