// Federation Gateway
class Gateway {
  private services: Map<string, ServiceClient> = new Map();

  registerService(name: string, client: ServiceClient): void {
    this.services.set(name, client);
  }

  async query(query: string, variables: any): Promise<any> {
    const parsedQuery = parseQuery(query);

    // Resolve entities from different services
    const results = await Promise.allSettled(
      parsedQuery.fields.map(field => 
        this.resolveField(field, variables)
      )
    );

    return results.map(result => {
      if (result.status === 'fulfilled') {
        return result.value;
      }
      throw result.reason;
    });
  }

  private async resolveField(field: FieldNode, variables: any): Promise<any> {
    const service = this.services.get(field.serviceName);
    if (!service) throw new Error(`Service ${field.serviceName} not found`);

    return service.query(field.operation, field.arguments);
  }
}

class BffServer {
  private routes: Map<string, RouteHandler> = new Map();
  private backendServices: Map<string, BackendClient> = new Map();

  registerRoute(path: string, method: string, handler: RouteHandler): void {
    this.routes.set(`${method.toUpperCase()}${path}`, handler);
  }

  registerBackend(name: string, client: BackendClient): void {
    this.backendServices.set(name, client);
  }

  async handleRequest(request: BffRequest): Promise<BffResponse> {
    const routeKey = `${request.method}:${request.path}`;
    const handler = this.routes.get(routeKey);

    if (!handler) {
      return { status: 404, body: { error: 'Not found' } };
    }

    return handler(request, this.backendServices);
  }
}

