        services.get('user-service').getProfile(req.userId),
        services.get('preference-service').getPreferences(req.userId),
        services.get('order-service').getRecentOrders(req.userId, 5)
      ]);

      return {
        status: 200,
        body: {
          user: {
            ...user,
            preferences,
            recentOrders: orders.map(o => ({
              id: o.id,
              total: o.total,
              status: o.status
            }))
          }
        }
      };
    });
  }
}

